        ) : SdkException() {
        override val message
            get() = "field=${ `field` }, value=${ `value` }, reason=${ `reason` }"
    }

    class Transport(

        val `reason`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "reason=${ `reason` }"
    }

    class Token(

