        ) : SdkException() {
        override val message
            get() = "reason=${ `reason` }"
    }

    class Body(

        val `reason`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "reason=${ `reason` }"
    }

    class Status(

        val `operation`: kotlin.String,

        val `status`: kotlin.UShort,

        val `body`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "operation=${ `operation` }, status=${ `status` }, body=${ `body` }"
    }

    class UnknownService(

        val `requested`: kotlin.String,

        val `available`: List<kotlin.String>
        ) : SdkException() {
        override val message
            get() = "requested=${ `requested` }, available=${ `available` }"
    }

    class InvalidServicePath(

        val `path`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "path=${ `path` }"
    }

    class ClaimFailed(

        val `phase`: kotlin.String,

        val `status`: kotlin.String
        ) : SdkException() {
        override val message
            get() = "phase=${ `phase` }, status=${ `status` }"
    }

    class ClaimTimeout(
        ) : SdkException() {
        override val message
            get() = ""
    }





    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<SdkException> {
        override fun lift(error_buf: RustBuffer.ByValue): SdkException = FfiConverterTypeSdkError.lift(error_buf)
    }


}

